const body = $input.first().json.body;
if (body.event !== 'access.expired') return [];

const d = body.data;
if (!d.customer.email) return [];

return [{
  json: {
    email: d.customer.email,
    userId: d.customer.userId,
    productName: d.product.name || 'produkt',
    productSlug: d.product.slug,
    productId: d.product.id,
    productIcon: d.product.icon || '',
    grantedAt: d.access.grantedAt,
    expiredAt: d.access.expiredAt
  }
}];
